import React from 'react';
import { CheckCircle2, Share2, Download, Copy } from 'lucide-react';
import { useCurrency } from '../context/CurrencyContext';

export default function TransactionReceiptScreen({ transaction, onDone, onShare }) {
  const { formatAmount } = useCurrency();

  return (
    <div className="h-full bg-gray-50 p-6 flex flex-col justify-center animate-in zoom-in-95 duration-300">
      <div className="bg-white rounded-[3rem] p-8 shadow-2xl relative overflow-hidden">
        {/* Top highlight bar */}
        <div className="absolute top-0 left-0 w-full h-3 bg-[#00875A]"></div>

        {/* Status */}
        <div className="flex flex-col items-center mb-10 mt-4">
          <div className="w-20 h-20 bg-emerald-50 text-[#00875A] rounded-full flex items-center justify-center mb-6 shadow-inner">
            <CheckCircle2 size={48} strokeWidth={2.5} />
          </div>
          <h2 className="text-xl font-black text-gray-900">Payment Successful</h2>
          <p className="text-4xl font-black mt-3 text-gray-900 tracking-tight">
            {formatAmount(transaction.amount)}
          </p>
        </div>

        {/* Transaction Details */}
        <div className="space-y-5 pt-6 border-t border-dashed border-gray-200">
          {[
            { label: 'Recipient/Source', value: transaction?.title || 'Nest Main Balance' },
            { label: 'Transaction ID', value: transaction?.id || 'TX-990201938', icon: Copy },
            { label: 'Date', value: transaction?.date || '31 Jan 2026, 09:05 AM' },
            { label: 'Payment Status', value: 'Completed', highlight: 'text-[#00875A]' },
          ].map((row, idx) => (
            <div key={idx} className="flex justify-between items-center text-sm">
              <span className="text-gray-400 font-bold uppercase tracking-wider text-[10px]">{row.label}</span>
              <div className="flex items-center gap-2">
                <span className={`font-black ${row.highlight || 'text-gray-900'}`}>{row.value}</span>
                {row.icon && <row.icon size={12} className="text-gray-300 cursor-pointer" />}
              </div>
            </div>
          ))}
        </div>

        {/* Actions: Share & Save */}
        <div className="flex gap-4 mt-12">
          <button className="flex-1 flex flex-col items-center gap-2 group">
            <div className="w-12 h-12 bg-gray-50 rounded-2xl flex items-center justify-center text-gray-600 group-active:scale-95 transition-transform">
              <Share2 size={20} />
            </div>
            <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Share</span>
          </button>
          <button className="flex-1 flex flex-col items-center gap-2 group">
            <div className="w-12 h-12 bg-gray-50 rounded-2xl flex items-center justify-center text-gray-600 group-active:scale-95 transition-transform">
              <Download size={20} />
            </div>
            <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Save PDF</span>
          </button>
        </div>
      </div>

      {/* Close button */}
      <button 
        onClick={onDone}
        className="mt-10 w-full py-4 rounded-2xl font-black text-white bg-gray-900 shadow-xl active:scale-95 transition-all"
      >
        Close Receipt
      </button>
    </div>
  );
}
